  verifyingKey: new Uint8Array(897).fill(2),
  publicKeyNtt: new Int32Array(512).fill(3),
}

const TX_HASH = TxHash.make(
  "0x7f3e2a1b9c4d5e6f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8091a2b3c4d"
)
